#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline class_T conv_int_classT(const int i) {
#ifdef ENABLE_HP
  return (half2)((half)i);
#else
  return (class_T)i;
#endif
}

inline class_T mad_classT(const class_T a, const class_T b, const class_T c) {
  return a * b + c;
}

inline int equal_classT(const class_T a, const class_T b) {
#ifdef ENABLE_HP
  return (a.s0 == b.s0) && (a.s1 == b.s1);
#else
  return a == b;
#endif
}

__kernel void benchmark_func(const class_T seed, __global class_T* g_data) {
  const size_t blockSize = (size_t)blockdim;

#ifdef BLOCK_STRIDED
  const size_t stride = blockSize;
  const size_t idx =
      get_group_id(0) * blockSize * (size_t)ELEMENTS_PER_THREAD +
      get_local_id(0);
  const size_t big_stride =
      get_num_groups(0) * blockSize * (size_t)ELEMENTS_PER_THREAD;
#else
  const size_t stride = get_global_size(0);
  const size_t idx = get_global_id(0);
  const size_t big_stride = get_global_size(0) * (size_t)ELEMENTS_PER_THREAD;
#endif

  class_T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < FUSION_DEGREE; k++) {
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];

      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = mad_classT(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = conv_int_classT(0);
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_classT(tmps[j], tmps[j + 1], sum);
    }

    if (equal_classT(sum, conv_int_classT(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}
